class Solution:
    def minInsertions(self, s: str) -> int:
        ans = 0
        cnt = 0
        for c in s:
            if c == '(':
                if cnt % 2 == 1:
                    ans += 1
                cnt += 1
            else:
                if cnt == 0:
                    ans += 1
                    cnt += 1
                cnt -= 1
        return ans + cnt
```
